from qiskit import QuantumCircuit, transpile
from qiskit.transpiler import CouplingMap
from qiskit.transpiler.preset_passmanagers import generate_preset_pass_manager

cmap = CouplingMap.from_line(4)
basis = ['cx', 'rz', 'sx', 'x']
edges = set()
for a, b in cmap.get_edges():
    edges.add((a, b)); edges.add((b, a))

def is_isa(qc):
    for ins in qc.data:
        n = ins.operation.name
        if n in ('barrier', 'measure'):
            continue
        if n not in basis:
            return False
        if ins.operation.num_qubits == 2:
            q = tuple(qc.find_bit(x).index for x in ins.qubits)
            if q not in edges:
                return False
    return True

def base():
    qc = QuantumCircuit(4); qc.h(0); qc.cx(0, 1); qc.cx(0, 2); qc.cx(0, 3); return qc

evidence = {}
proven = []
def check(key, fn):
    try:
        out = fn()
        ok = is_isa(out)
        evidence[key] = f"produced circuit ops={dict(out.count_ops())}; is_isa={ok}"
        if ok:
            proven.append(key)
    except Exception as e:
        evidence[key] = f"raised {type(e).__name__}: {str(e)[:90]}"

check("A", lambda: generate_preset_pass_manager(optimization_level=1).run(base()))
check("B", lambda: transpile(base()))
check("C", lambda: generate_preset_pass_manager(1, backend='ibm_target').run(base()))
check("D", lambda: generate_preset_pass_manager(optimization_level=1, basis_gates=basis, coupling_map=cmap).run(base()))
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"proven": proven}})
